class AllOne {
    private HashMap<String, Integer> countMap;
    private HashMap<Integer, TreeSet<String>> keyMap;
    private int minCount;
    private int maxCount;

    public AllOne() {
        countMap = new HashMap<>();
        keyMap = new HashMap<>();
        minCount = 0;
        maxCount = 0;
    }

    public void inc(String key) {
        int count = countMap.getOrDefault(key, 0) + 1;
        countMap.put(key, count);

        if (keyMap.containsKey(count - 1)) {
            TreeSet<String> set = keyMap.get(count - 1);
            set.remove(key);
            if (set.isEmpty()) {
                keyMap.remove(count - 1);
            }
        }

        if (!keyMap.containsKey(count)) {
            keyMap.put(count, new TreeSet<>());
        }
        keyMap.get(count).add(key);

        if (count > maxCount) {
            maxCount = count;
        }

        if (count == 1) {
            minCount = 1;
        } else if (countMap.get(key) == 1) {
            minCount = 1;
        }

        if (countMap.get(key) > 1 && !keyMap.containsKey(count - 1)) {
            if (minCount == count - 1) {
                minCount = count;
            }
        }
    }

    public void dec(String key) {
        int count = countMap.get(key) - 1;
        countMap.put(key, count);

        if (keyMap.containsKey(count + 1)) {
            TreeSet<String> set = keyMap.get(count + 1);
            set.remove(key);
            if (set.isEmpty()) {
                keyMap.remove(count + 1);
            }
        }

        if (count > 0) {
            if (!keyMap.containsKey(count)) {
                keyMap.put(count, new TreeSet<>());
            }
            keyMap.get(count).add(key);
        } else {
            countMap.remove(key);
        }

        if (countMap.isEmpty()) {
            minCount = 0;
            maxCount = 0;
        } else if (count == 0) {
            if (minCount == count + 1) {
                minCount = keyMap.containsKey(1) ? 1 : minCount + 1;
            }
            if (maxCount == count + 1) {
                maxCount = keyMap.containsKey(maxCount - 1) ? maxCount - 1 : maxCount;
            }
        }
    }

    public String getMaxKey() {
        if (maxCount == 0) {
            return "";
        }
        return keyMap.get(maxCount).first();
    }

    public String getMinKey() {
        if (minCount == 0) {
            return "";
        }
        return keyMap.get(minCount).first();
    }
}
